import React from 'react';
import styled from 'styled-components';
import { useTranslation } from 'react-i18next';

const Card = styled.div`
  display: flex;
  flex-direction: column;
  background-color: ${({ theme }) => theme.colors.background};
  border-radius: ${({ theme }) => theme.borderRadius.lg};
  overflow: hidden;
  box-shadow: ${({ theme }) => theme.shadows.md};
  height: 100%;
  position: relative;

  @media (prefers-color-scheme: dark) {
    background-color: #1e1e1e;
  }

  @media (max-width: 480px) {
    border-radius: ${({ theme }) => theme.borderRadius.md};
  }
`;

const ImageContainer = styled.div`
  position: relative;
  padding-top: 75%; /* 4:3 aspect ratio */
  overflow: hidden;
`;

const ProductImage = styled.img`
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.3s ease;

  ${Card}:hover & {
    transform: scale(1.05);
  }
`;

const DiscountBadge = styled.div`
  position: absolute;
  top: 1rem;
  right: 1rem;
  background-color: ${({ theme }) => theme.colors.discount};
  color: white;
  padding: 0.25rem 0.75rem;
  border-radius: ${({ theme }) => theme.borderRadius.full};
  font-weight: 600;
  font-size: ${({ theme }) => theme.fontSizes.sm};
  z-index: 1;

  @media (max-width: 480px) {
    top: 0.75rem;
    right: 0.75rem;
    padding: 0.2rem 0.6rem;
    font-size: 0.7rem;
  }
`;

const ProductInfo = styled.div`
  padding: 1.25rem;
  flex: 1;
  display: flex;
  flex-direction: column;

  @media (max-width: 480px) {
    padding: 1rem;
  }
`;

const ProductName = styled.h3`
  font-size: ${({ theme }) => theme.fontSizes.md};
  font-weight: 600;
  margin-bottom: 0.5rem;
  color: ${({ theme }) => theme.colors.text};

  @media (max-width: 480px) {
    font-size: 0.95rem;
    margin-bottom: 0.3rem;
  }
`;

const ProductCategory = styled.p`
  font-size: ${({ theme }) => theme.fontSizes.xs};
  color: ${({ theme }) => theme.colors.textLight};
  margin-bottom: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.5px;

  @media (max-width: 480px) {
    font-size: 0.65rem;
    margin-bottom: 0.5rem;
    letter-spacing: 0.3px;
  }
`;

const PriceContainer = styled.div`
  display: flex;
  align-items: baseline;
  gap: 0.5rem;
  margin-top: auto;

  @media (max-width: 480px) {
    gap: 0.3rem;
    flex-wrap: wrap;
  }
`;

const CurrentPrice = styled.span`
  font-size: ${({ theme }) => theme.fontSizes.lg};
  font-weight: 700;
  color: ${({ theme }) => theme.colors.primary};

  @media (max-width: 480px) {
    font-size: 1.1rem;
  }
`;

const OriginalPrice = styled.span`
  font-size: ${({ theme }) => theme.fontSizes.sm};
  color: ${({ theme }) => theme.colors.textLight};
  text-decoration: line-through;

  @media (max-width: 480px) {
    font-size: 0.8rem;
  }
`;

const DiscountStat = styled.div`
  display: flex;
  flex-direction: row;
  align-items: center;
  gap: 0.5rem;

  @media (max-width: 480px) {
    margin-right: 1rem;
    margin-bottom: 0.5rem;
  }
`;

const StatLabel = styled.span`
  font-size: ${({ theme }) => theme.fontSizes.xs};
  color: ${({ theme }) => theme.colors.textLight};
  white-space: nowrap;
`;

const StatValue = styled.span`
  font-size: ${({ theme }) => theme.fontSizes.md};
  font-weight: 600;
  color: ${({ theme }) => theme.colors.primary};

  @media (max-width: 480px) {
    font-size: 0.95rem;
  }
`;

const WoltButton = styled.a`
  display: block;
  margin-top: 1rem;
  padding: 0.75rem;
  background-color: #00C2E8; /* Wolt blue */
  color: white;
  text-align: center;
  font-weight: 500;
  border-radius: ${({ theme }) => theme.borderRadius.md};
  transition: background-color 0.2s ease;

  &:hover {
    background-color: #00A8CC;
  }

  @media (max-width: 480px) {
    margin-top: 0.75rem;
    padding: 0.6rem;
    font-size: 0.9rem;
  }
`;

const ProductCard = ({ product, store }) => {
  const { t } = useTranslation();

  const woltUrl = `https://wolt.com/en/geo/${store.city}/venue/${store.slug}/itemid-${product.id_venue}`;
  const imageUrl = product.image_url || '/images/default-product.jpg';

  return (
    <Card>
      <ImageContainer>
        <ProductImage src={imageUrl} alt={product.name} />
        <DiscountBadge>-{Math.round(product.discount_percentage)}%</DiscountBadge>
      </ImageContainer>

      <ProductInfo>
        <ProductName>{product.name}</ProductName>
        {product.category && <ProductCategory>{product.category}</ProductCategory>}

        <PriceContainer>
          <CurrentPrice>{product.current_price} {product.currency}</CurrentPrice>
          {product.original_price > 0 && (
            <OriginalPrice>{product.original_price} {product.currency}</OriginalPrice>
          )}
          <DiscountStat>
            <StatLabel>{t('discountCount')}</StatLabel>
            <StatValue>{store.discount_count}</StatValue>
          </DiscountStat>
        </PriceContainer>

        <WoltButton href={woltUrl} target="_blank" rel="noopener noreferrer">
          {t('openInWolt')}
        </WoltButton>
      </ProductInfo>
    </Card>
  );
};

export default ProductCard;
